     1→import { Building2 as Building, Clock as Clock, Briefcase as Briefcase, Calendar as Calendar, Trash2 as Trash2 } from "lucide-react";
     2→import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
     3→import { PageHeader } from "@/components/layout/PageHeader";
     4→import { getSalonNavItems } from "@/config/navigation";
     5→import { useAuth } from "@/contexts/AuthContext";
     6→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
     7→import { useNavigate } from "react-router-dom";
     8→import { useState } from "react";
     9→import {
    10→  AlertDialog,
    11→  AlertDialogAction,
    12→  AlertDialogCancel,
    13→  AlertDialogContent,
    14→  AlertDialogDescription,
    15→  AlertDialogFooter,
    16→  AlertDialogHeader,
    17→  AlertDialogTitle,
    18→} from "@/components/ui/alert-dialog";
    19→import { Button } from "@/components/ui/button";
    20→import { useToast } from "@/hooks/use-toast";
    21→import { salonService } from "@/services/salonService";
    22→type LucideIcon = React.ComponentType<{ size?: number; stroke?: number; className?: string; }>;
    23→
    24→const PLATFORM_ADMIN_EMAIL = "adm@easy.com.br";
    25→
    26→interface SettingItem {
    27→  title: string;
    28→  description: string;
    29→  icon: LucideIcon;
    30→  href: string;
    31→}
    32→
    33→const settingsItems: SettingItem[] = [
    34→  {
    35→    title: "Dados do Salão",
    36→    description: "Informações básicas, endereço e contato",
    37→    icon: Building,
    38→    href: "/salon/settings/salon-data",
    39→  },
    40→  {
    41→    title: "Horário de Funcionamento",
    42→    description: "Configure os dias e horários de atendimento",
    43→    icon: Clock,
    44→    href: "/salon/settings/working-hours",
    45→  },
    46→  {
    47→    title: "Gestão de Especialidades",
    48→    description: "Visualize e gerencie as especialidades do salão",
    49→    icon: Briefcase,
    50→    href: "/salon/specialties",
    51→  },
    52→  {
    53→    title: "Agendamento Online",
    54→    description: "Configure as regras do agendamento online",
    55→    icon: Calendar,
    56→    href: "/salon/settings/online-booking",
    57→  },
    58→  {
    59→    title: "Horários do Agendamento Online",
    60→    description: "Configure horários específicos para o agendamento online",
    61→    icon: Clock,
    62→    href: "/salon/settings/online-booking-hours",
    63→  },
    64→];
    65→
    66→export default function SettingsPage() {
    67→  const { selectedSalon } = useSelectedSalon();
    68→  const { user } = useAuth();
    69→  const navigate = useNavigate();
    70→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
    71→  const [isDeleting, setIsDeleting] = useState(false);
    72→  const { toast } = useToast();
    73→
    74→  const navItems = getSalonNavItems(user?.role || "Profissional");
    75→
    76→  const handleNavigateToSetting = (href: string): void => {
    77→    navigate(href);
    78→  };
    79→
    80→  const handleDeleteSalon = async (): Promise<void> => {
    81→    if (!selectedSalon) return;
    82→
    83→    setIsDeleting(true);
    84→    try {
    85→      await salonService.deleteSalon(selectedSalon.id);
    86→      toast({
    87→        title: "Salão excluído com sucesso",
    88→        description: "O salão foi removido permanentemente.",
    89→      });
    90→      navigate("/admin/salons");
    91→    } catch (error: unknown) {
    92→      toast({
    93→        title: "Erro ao excluir salão",
    94→        description:
    95→          error instanceof Error
    96→            ? error.message
    97→            : "Não foi possível excluir o salão. Tente novamente.",
    98→        variant: "destructive",
    99→      });
   100→    } finally {
   101→      setIsDeleting(false);
   102→      setShowDeleteDialog(false);
   103→    }
   104→  };
   105→
   106→  return (
   107→    <EasySalonLayout
   108→      sideNavTitle="Easy Salon"
   109→      sideNavSubtitle={selectedSalon?.name || "Salão"}
   110→      sideNavItems={navItems}
   111→    >
   112→      <PageHeader
   113→        title="Configurações"
   114→        subtitle="Gerencie as configurações do seu salão"
   115→        disabledActions={!selectedSalon?.active}
   116→      />
   117→
   118→      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
   119→        {settingsItems.map((item) => {
   120→          const Icon = item.icon;
   121→          return (
   122→            <div
   123→              key={item.href}
   124→              className="bg-card border border-border rounded-3xl p-5 cursor-pointer hover:shadow-md transition-shadow"
   125→              onClick={() => handleNavigateToSetting(item.href)}
   126→            >
   127→              <div className="flex items-center gap-4 mb-3">
   128→                <div className="p-2 bg-secondary rounded-lg">
   129→                  <Icon className="h-6 w-6 text-primary" />
   130→                </div>
   131→                <h3 className="text-base font-semibold text-foreground">{item.title}</h3>
   132→              </div>
   133→              <p className="text-sm text-muted-foreground">{item.description}</p>
   134→            </div>
   135→          );
   136→        })}
   137→      </div>
   138→
   139→      {user?.email === PLATFORM_ADMIN_EMAIL && (
   140→        <div className="mt-8 p-6 border border-destructive/20 rounded-lg bg-destructive/5">
   141→          <div className="flex items-center justify-between">
   142→            <div>
   143→              <h3 className="text-lg font-semibold text-destructive">
   144→                Zona de Perigo
   145→              </h3>
   146→              <p className="text-sm text-muted-foreground mt-1">
   147→                Ações irreversíveis que afetam permanentemente o salão
   148→              </p>
   149→            </div>
   150→            <Button
   151→              variant="destructive"
   152→              onClick={() => setShowDeleteDialog(true)}
   153→              className="gap-2"
   154→            >
   155→              <Trash2 className="h-4 w-4" />
   156→              Excluir Salão
   157→            </Button>
   158→          </div>
   159→        </div>
   160→      )}
   161→
   162→      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
   163→        <AlertDialogContent className="w-[95vw] md:max-w-lg rounded-xl md:rounded-lg border-none shadow-2xl">
   164→          <AlertDialogHeader>
   165→            <AlertDialogTitle>
   166→              Tem certeza que deseja excluir este salão?
   167→            </AlertDialogTitle>
   168→            <AlertDialogDescription>
   169→              Esta ação não pode ser desfeita. Todos os dados do salão,
   170→              incluindo agendamentos, serviços, usuários e configurações serão
   171→              permanentemente excluídos do sistema.
   172→            </AlertDialogDescription>
   173→          </AlertDialogHeader>
   174→          <AlertDialogFooter className="flex-col-reverse sm:flex-row gap-2">
   175→            <AlertDialogCancel disabled={isDeleting} className="w-full sm:w-auto">
   176→              Cancelar
   177→            </AlertDialogCancel>
   178→            <AlertDialogAction
   179→              onClick={handleDeleteSalon}
   180→              disabled={isDeleting}
   181→              className="w-full sm:w-auto bg-destructive hover:bg-destructive/90"
   182→            >
   183→              {isDeleting ? "Excluindo..." : "Excluir Permanentemente"}
   184→            </AlertDialogAction>
   185→          </AlertDialogFooter>
   186→        </AlertDialogContent>
   187→      </AlertDialog>
   188→    </EasySalonLayout>
   189→  );
   190→}
   191→

