     1→import { useState, useEffect, useCallback } from "react";
     2→import { useNavigate } from "react-router-dom";
     3→import { Pencil as Edit, Clock as Clock, Briefcase as Briefcase, Lock as Lock, UserX as UserX, Trash2 as Trash2, Search as Search } from "lucide-react";
     4→import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
     5→import { PageHeader } from "@/components/layout/PageHeader";
     6→import { DataTable } from "@/components/ui/data-table";
     7→import { Button } from "@/components/ui/button";
     8→import { Badge } from "@/components/ui/badge";
     9→import { Input } from "@/components/ui/input";
    10→import {
    11→  Select,
    12→  SelectContent,
    13→  SelectItem,
    14→  SelectTrigger,
    15→  SelectValue,
    16→} from "@/components/ui/select";
    17→import {
    18→  AlertDialog,
    19→  AlertDialogAction,
    20→  AlertDialogCancel,
    21→  AlertDialogContent,
    22→  AlertDialogDescription,
    23→  AlertDialogFooter,
    24→  AlertDialogHeader,
    25→  AlertDialogTitle,
    26→  AlertDialogTrigger,
    27→} from "@/components/ui/alert-dialog";
    28→import { getSalonNavItems } from "@/config/navigation";
    29→import { useAuth } from "@/contexts/AuthContext";
    30→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
    31→import { userService } from "@/services/userService";
    32→import { User, UserRole } from "@/types/user";
    33→import { toast } from "sonner";
    34→import { getErrorMessage } from "@/utils/error";
    35→import { useDebouncedValue } from "@/hooks/useDebouncedValue";
    36→import { formatPhone } from "@/utils/formatters";
    37→import { ResponsivePagination } from "@/components/ui/responsive-pagination";
    38→
    39→export default function SalonUsersPage() {
    40→  const navigate = useNavigate();
    41→  const { selectedSalon } = useSelectedSalon();
    42→  const { user } = useAuth();
    43→  const [users, setUsers] = useState<User[]>([]);
    44→  const [loading, setLoading] = useState(true);
    45→  const [searchTerm, setSearchTerm] = useState("");
    46→  const debouncedSearchTerm = useDebouncedValue(searchTerm, 500);
    47→  const [statusFilter, setStatusFilter] = useState<string>("all");
    48→  const [currentPage, setCurrentPage] = useState(1);
    49→  const [totalPages, setTotalPages] = useState(1);
    50→  const [totalItems, setTotalItems] = useState(0);
    51→  const [pageSize, setPageSize] = useState(16);
    52→
    53→  const navItems = getSalonNavItems(user?.role || "Profissional");
    54→
    55→  const loadUsers = useCallback(
    56→    async (
    57→      page: number = 1,
    58→      search?: string,
    59→      status?: string,
    60→      limit: number = pageSize
    61→    ): Promise<void> => {
    62→      try {
    63→        setLoading(true);
    64→        const searchParam = search && search.trim() ? search.trim() : undefined;
    65→        const params = {
    66→          salonId: selectedSalon?.id,
    67→          search: searchParam,
    68→          status: status && status !== "all" ? (status as "active" | "inactive") : undefined,
    69→          page,
    70→          limit,
    71→          sortBy: "name",
    72→          sortOrder: "asc" as const,
    73→        };
    74→
    75→        const response = await userService.list(params);
    76→
    77→        // Filter to show only salon-level roles (Manager, Professional and Receptionist)
    78→        // Exclude platform admin roles (super_admin, tenant_admin) and client role
    79→        const filteredUsers = response.data.filter(
    80→          (user) =>
    81→            user.role === "manager" ||
    82→            user.role === "professional" ||
    83→            user.role === "receptionist"
    84→        );
    85→        setUsers(filteredUsers);
    86→        setTotalPages(
    87→          response.totalPages ||
    88→            Math.ceil((response.total || filteredUsers.length) / limit)
    89→        );
    90→        setTotalItems(response.total || filteredUsers.length);
    91→      } catch (error) {
    92→        toast.error(getErrorMessage(error) || "Erro ao carregar usuários.");
    93→        setUsers([]);
    94→      } finally {
    95→        setLoading(false);
    96→      }
    97→    },
    98→    [selectedSalon?.id, pageSize]
    99→  );
   100→
   101→  // Load users from backend with debounce for search
   102→  useEffect(() => {
   103→    // Garantir que a página comece no topo (especialmente no mobile)
   104→    window.scrollTo(0, 0);
   105→  }, []);
   106→
   107→  useEffect(() => {
   108→    if (selectedSalon?.id) {
   109→      loadUsers(currentPage, debouncedSearchTerm, statusFilter, pageSize);
   110→    }
   111→  }, [
   112→    selectedSalon?.id,
   113→    currentPage,
   114→    debouncedSearchTerm,
   115→    statusFilter,
   116→    pageSize,
   117→  ]);
   118→
   119→  // Reset to first page when search or filter changes
   120→  useEffect(() => {
   121→    setCurrentPage(1);
   122→  }, [debouncedSearchTerm, statusFilter]);
   123→
   124→  const handleNewUser = (): void => {
   125→    navigate("/salon/users/create");
   126→  };
   127→
   128→  const handleEditUser = (user: User): void => {
   129→    navigate(`/salon/users/edit/${user.id}`);
   130→  };
   131→
   132→  const handleUserSchedule = (user: User): void => {
   133→    navigate(`/salon/users/${user.id}/schedule`);
   134→  };
   135→
   136→  const handleUserServices = (user: User): void => {
   137→    navigate(`/salon/users/${user.id}/services`);
   138→  };
   139→
   140→  const handleUserPassword = (user: User): void => {
   141→    navigate(`/salon/users/${user.id}/password`);
   142→  };
   143→
   144→  const handleToggleUserStatus = async (user: User): Promise<void> => {
   145→    try {
   146→      setLoading(true);
   147→      const newStatus = !user.active;
   148→      await userService.update(user.id, { active: newStatus });
   149→
   150→      toast.success(
   151→        `Usuário ${newStatus ? "ativado" : "desativado"} com sucesso!`
   152→      );
   153→      loadUsers(currentPage, debouncedSearchTerm, statusFilter, pageSize);
   154→    } catch (error) {
   155→      toast.error(
   156→        getErrorMessage(error) || "Erro ao alterar status do usuário."
   157→      );
   158→    } finally {
   159→      setLoading(false);
   160→    }
   161→  };
   162→
   163→  const handleDeleteUser = async (user: User): Promise<void> => {
   164→    try {
   165→      setLoading(true);
   166→      await userService.delete(user.id);
   167→
   168→      toast.success("Usuário excluído com sucesso!");
   169→      loadUsers(currentPage, debouncedSearchTerm, statusFilter, pageSize);
   170→    } catch (error) {
   171→      toast.error(getErrorMessage(error) || "Erro ao excluir usuário.");
   172→    } finally {
   173→      setLoading(false);
   174→    }
   175→  };
   176→
   177→  const handlePageSizeChange = (value: string): void => {
   178→    const newPageSize = Number(value);
   179→    setPageSize(newPageSize);
   180→    setCurrentPage(1);
   181→  };
   182→
   183→  const getRoleLabel = (role: UserRole): string => {
   184→    return userService.getRoleLabel(role);
   185→  };
   186→
   187→  const columns = [
   188→    {
   189→      key: "nickname" as keyof User,
   190→      header: "Apelido",
   191→      render: (value: string | undefined): string => value || "-",
   192→    },
   193→    {
   194→      key: "name" as keyof User,
   195→      header: "Nome",
   196→    },
   197→    {
   198→      key: "role" as keyof User,
   199→      header: "Perfil",
   200→      render: (value: UserRole): string => getRoleLabel(value),
   201→    },
   202→    {
   203→      key: "email" as keyof User,
   204→      header: "Email",
   205→    },
   206→    {
   207→      key: "whatsapp" as keyof User,
   208→      header: "WhatsApp",
   209→      render: (value: string | undefined): string => value ? formatPhone(value) : "-",
   210→    },
   211→    {
   212→      key: "active" as keyof User,
   213→      header: "Status",
   214→      render: (value: boolean): JSX.Element => (
   215→        <Badge className={value ? "salon-badge-active" : "salon-badge-inactive"}>
   216→          {value ? "Ativo" : "Inativo"}
   217→        </Badge>
   218→      ),
   219→    },
   220→    {
   221→      key: "id" as keyof User,
   222→      header: "Ações",
   223→      className: "text-right",
   224→      render: (_value: string, row: User): JSX.Element => (
   225→        <div className="flex items-center justify-end gap-1">
   226→          <Button
   227→            variant="ghost"
   228→            size="sm"
   229→            onClick={() => handleEditUser(row)}
   230→            className="h-7 w-7 p-0"
   231→            title="Editar dados básicos"
   232→          >
   233→            <Edit className="h-3 w-3" />
   234→          </Button>
   235→          {/* Botões de horários e serviços só para profissionais */}
   236→          {row.role === "professional" && (
   237→            <>
   238→              <Button
   239→                variant="ghost"
   240→                size="sm"
   241→                onClick={() => handleUserSchedule(row)}
   242→                className="h-7 w-7 p-0"
   243→                title="Gerenciar horários"
   244→              >
   245→                <Clock className="h-3 w-3" />
   246→              </Button>
   247→              <Button
   248→                variant="ghost"
   249→                size="sm"
   250→                onClick={() => handleUserServices(row)}
   251→                className="h-7 w-7 p-0"
   252→                title="Gerenciar serviços"
   253→              >
   254→                <Briefcase className="h-3 w-3" />
   255→              </Button>
   256→            </>
   257→          )}
   258→          <Button
   259→            variant="ghost"
   260→            size="sm"
   261→            onClick={() => handleUserPassword(row)}
   262→            className="h-7 w-7 p-0"
   263→            disabled={!selectedSalon?.active}
   264→            title="Alterar senha"
   265→          >
   266→            <Lock className="h-3 w-3" />
   267→          </Button>
   268→          <Button
   269→            variant="ghost"
   270→            size="sm"
   271→            disabled={!selectedSalon?.active}
   272→            onClick={() => handleToggleUserStatus(row)}
   273→            className={`h-7 w-7 p-0 ${
   274→              row.active
   275→                ? "text-orange-600 hover:text-orange-700"
   276→                : "text-green-600 hover:text-green-700"
   277→            }`}
   278→            title={row.active ? "Desativar usuário" : "Ativar usuário"}
   279→          >
   280→            <UserX className="h-3 w-3" />
   281→          </Button>
   282→          <AlertDialog>
   283→            <AlertDialogTrigger asChild>
   284→              <Button
   285→                variant="ghost"
   286→                size="sm"
   287→                disabled={!selectedSalon?.active}
   288→                className="h-7 w-7 p-0 text-red-600 hover:text-red-700"
   289→                title="Excluir usuário"
   290→              >
   291→                <Trash2 className="h-3 w-3" />
   292→              </Button>
   293→            </AlertDialogTrigger>
   294→            <AlertDialogContent className="w-[95vw] max-w-[400px] rounded-xl md:rounded-lg p-6 gap-6"> {/* RESP: AlertDialog adaptado */}
   295→              <AlertDialogHeader className="text-left">
   296→                <AlertDialogTitle className="text-xl font-bold">Excluir usuário</AlertDialogTitle>
   297→                <AlertDialogDescription className="text-base pt-2">
   298→                  Tem certeza que deseja excluir o usuário "{row.name}"? Esta
   299→                  ação não pode ser desfeita.
   300→                </AlertDialogDescription>
   301→              </AlertDialogHeader>
   302→              <AlertDialogFooter className="flex flex-col-reverse sm:flex-row gap-3"> {/* RESP: Footer empilhado no mobile */}
   303→                <AlertDialogCancel className="w-full sm:w-auto mt-0">Cancelar</AlertDialogCancel>
   304→                <AlertDialogAction
   305→                  onClick={() => handleDeleteUser(row)}
   306→                  className="w-full sm:w-auto bg-destructive hover:bg-destructive/90 shadow-md transition-all active:scale-[0.98]"
   307→                >
   308→                  Excluir
   309→                </AlertDialogAction>
   310→              </AlertDialogFooter>
   311→            </AlertDialogContent>
   312→          </AlertDialog>
   313→        </div>
   314→      ),
   315→    },
   316→  ];
   317→
   318→  return (
   319→    <EasySalonLayout
   320→      sideNavTitle="Easy Salon"
   321→      sideNavSubtitle={selectedSalon?.name || "Salão"}
   322→      sideNavItems={navItems}
   323→    >
   324→      <PageHeader
   325→        title="Usuários do Salão"
   326→        disabledActions={!selectedSalon?.active}
   327→        action={{
   328→          label: "Novo Usuário",
   329→          onClick: handleNewUser,
   330→        }}
   331→      />
   332→
   333→      {/* Barra de Ferramentas Responsiva */}
   334→      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
   335→        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
   336→          <div className="relative w-full sm:max-w-sm">
   337→            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
   338→            <Input
   339→              type="text"
   340→              placeholder="Buscar por nome ou email..."
   341→              value={searchTerm}
   342→              onChange={(e) => setSearchTerm(e.target.value)}
   343→              className="pl-10 salon-input"
   344→            />
   345→          </div>
   346→          <div className="flex items-center gap-2 w-full sm:w-auto">
   347→            <label htmlFor="status-filter" className="text-xs font-semibold whitespace-nowrap">
   348→              Status:
   349→            </label>
   350→            <Select value={statusFilter} onValueChange={setStatusFilter}>
   351→              <SelectTrigger className="w-full sm:w-[150px] salon-input">
   352→                <SelectValue placeholder="Status" />
   353→              </SelectTrigger>
   354→              <SelectContent>
   355→                <SelectItem value="all">Todos</SelectItem>
   356→                <SelectItem value="active">Ativos</SelectItem>
   357→                <SelectItem value="inactive">Inativos</SelectItem>
   358→              </SelectContent>
   359→            </Select>
   360→          </div>
   361→        </div>
   362→      </div>
   363→
   364→      {loading ? (
   365→        <div className="flex justify-center items-center h-64">
   366→          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
   367→        </div>
   368→      ) : users.length === 0 ? (
   369→        <div className="text-center py-12">
   370→          <p className="text-muted-foreground mb-4">
   371→            {searchTerm || statusFilter !== "all"
   372→              ? "Nenhum usuário encontrado com os filtros aplicados."
   373→              : "Nenhum usuário cadastrado ainda."}
   374→          </p>
   375→          {!searchTerm && statusFilter === "all" && (
   376→            <Button onClick={handleNewUser}>Cadastrar Primeiro Usuário</Button>
   377→          )}
   378→        </div>
   379→      ) : (
   380→        <>
   381→          <DataTable 
   382→            data={users} 
   383→            columns={columns} 
   384→            mobileView="cards"
   385→            mobileCardConfig={{
