          <Button
            variant="ghost"
            size="sm"
            onClick={() => handleUserPassword(row)}
            className="h-7 w-7 p-0"
            disabled={!selectedSalon?.active}
            title="Alterar senha"
          >
            <Lock className="h-3 w-3" />
          </Button>
          <Button
            variant="ghost"
            size="sm"
            disabled={!selectedSalon?.active}
            onClick={() => handleToggleUserStatus(row)}
            className={`h-7 w-7 p-0 ${
              row.active
                ? "text-orange-600 hover:text-orange-700"
                : "text-green-600 hover:text-green-700"
            }`}
            title={row.active ? "Desativar usuário" : "Ativar usuário"}
          >
            <UserX className="h-3 w-3" />
          </Button>
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <Button
                variant="ghost"
                size="sm"
                disabled={!selectedSalon?.active}
                className="h-7 w-7 p-0 text-red-600 hover:text-red-700"
                title="Excluir usuário"
              >
                <Trash2 className="h-3 w-3" />
              </Button>
            </AlertDialogTrigger>
            <AlertDialogContent className="w-[95vw] max-w-[400px] rounded-xl md:rounded-lg p-6 gap-6"> {/* RESP: AlertDialog adaptado */}
              <AlertDialogHeader className="text-left">
                <AlertDialogTitle className="text-xl font-bold">Excluir usuário</AlertDialogTitle>
                <AlertDialogDescription className="text-base pt-2">
                  Tem certeza que deseja excluir o usuário "{row.name}"? Esta
                  ação não pode ser desfeita.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter className="flex flex-col-reverse sm:flex-row gap-3"> {/* RESP: Footer empilhado no mobile */}
                <AlertDialogCancel className="w-full sm:w-auto mt-0">Cancelar</AlertDialogCancel>
                <AlertDialogAction
                  onClick={() => handleDeleteUser(row)}
                  className="w-full sm:w-auto bg-destructive hover:bg-destructive/90 shadow-md transition-all active:scale-[0.98]"
                >
                  Excluir
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        </div>
      ),
    },
  ];

  return (
    <EasySalonLayout
      sideNavTitle="Easy Salon"
      sideNavSubtitle={selectedSalon?.name || "Salão"}
      sideNavItems={navItems}
    >
      <PageHeader
        title="Usuários do Salão"
        disabledActions={!selectedSalon?.active}
        action={{
          label: "Novo Usuário",
          onClick: handleNewUser,
        }}
      />

      {/* Barra de Ferramentas Responsiva */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
        <div className="flex flex-col sm:flex-row items-center gap-4 w-full md:w-auto">
          <div className="relative w-full sm:max-w-sm">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
            <Input
              type="text"
              placeholder="Buscar por nome ou email..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 salon-input"
            />
          </div>
          <div className="flex items-center gap-2 w-full sm:w-auto">
            <label htmlFor="status-filter" className="text-xs font-semibold whitespace-nowrap">
              Status:
            </label>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="w-full sm:w-[150px] salon-input">
                <SelectValue placeholder="Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Todos</SelectItem>
                <SelectItem value="active">Ativos</SelectItem>
                <SelectItem value="inactive">Inativos</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center items-center h-64">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
        </div>
      ) : users.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-muted-foreground mb-4">
            {searchTerm || statusFilter !== "all"
              ? "Nenhum usuário encontrado com os filtros aplicados."
              : "Nenhum usuário cadastrado ainda."}
          </p>
          {!searchTerm && statusFilter === "all" && (
            <Button onClick={handleNewUser}>Cadastrar Primeiro Usuário</Button>
          )}
        </div>
      ) : (
        <>
          <DataTable 
            data={users} 
            columns={columns} 
            mobileView="cards"
            mobileCardConfig={{
              title: "nickname",
              subtitle: "email",
              badge: "role",
            }}
          />

          <ResponsivePagination
            currentPage={currentPage}
            totalPages={totalPages}
            totalItems={totalItems}
            pageSize={pageSize}
            onPageChange={setCurrentPage}
            onPageSizeChange={(size) => handlePageSizeChange(String(size))}
          />
        </>
      )}
    </EasySalonLayout>
  );
}
