```typescript
import { Building2 as Building, Clock as Clock, Briefcase as Briefcase, Calendar as Calendar, Trash2 as Trash2 } from "lucide-react";
import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
import { PageHeader } from "@/components/layout/PageHeader";
import { getSalonNavItems } from "@/config/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { useSelectedSalon } from "@/hooks/useSelectedSalon";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { salonService } from "@/services/salonService";
type LucideIcon = React.ComponentType<{ size?: number; stroke?: number; className?: string; }>;

const PLATFORM_ADMIN_EMAIL = "adm@easy.com.br";

interface SettingItem {
  title: string;
  description: string;
  icon: LucideIcon;
  href: string;
}

const settingsItems: SettingItem[] = [
  {
    title: "Dados do Salão",
    description: "Informações básicas, endereço e contato",
    icon: Building,
    href: "/salon/settings/salon-data",
  },
  {
    title: "Horário de Funcionamento",
    description: "Configure os dias e horários de atendimento",
    icon: Clock,
    href: "/salon/settings/working-hours",
  },
  {
    title: "Gestão de Especialidades",
    description: "Visualize e gerencie as especialidades do salão",
    icon: Briefcase,
    href: "/salon/specialties",
  },
  {
    title: "Agendamento Online",
    description: "Configure as regras do agendamento online",
    icon: Calendar,
    href: "/salon/settings/online-booking",
  },
  {
    title: "Horários do Agendamento Online",
    description: "Configure horários específicos para o agendamento online",
    icon: Clock,
    href: "/salon/settings/online-booking-hours",
  },
];

export default function SettingsPage() {
  const { selectedSalon } = useSelectedSalon();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const { toast } = useToast();

  const navItems = getSalonNavItems(user?.role || "Profissional");

  const handleNavigateToSetting = (href: string): void => {
    navigate(href);
  };

  const handleDeleteSalon = async (): Promise<void> => {
    if (!selectedSalon) return;

    setIsDeleting(true);
    try {
      await salonService.deleteSalon(selectedSalon.id);
      toast({
        title: "Salão excluído com sucesso",
        description: "O salão foi removido permanentemente.",
      });
      navigate("/admin/salons");
    } catch (error: unknown) {
      toast({
        title: "Erro ao excluir salão",
        description:
          error instanceof Error
            ? error.message
            : "Não foi possível excluir o salão. Tente novamente.",
        variant: "destructive",
      });
    } finally {
      setIsDeleting(false);
      setShowDeleteDialog(false);
    }
  };

  return (
    <EasySalonLayout
      sideNavTitle="Easy Salon"
      sideNavSubtitle={selectedSalon?.name || "Salão"}
      sideNavItems={navItems}
    >
      <PageHeader
        title="Configurações"
        subtitle="Gerencie as configurações do seu salão"
        disabledActions={!selectedSalon?.active}
      />

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {settingsItems.map((item) => {
          const Icon = item.icon;
          return (
            <div
              key={item.href}
              className="bg-card border border-border rounded-3xl p-5 cursor-pointer hover:shadow-md transition-shadow"
              onClick={() => handleNavigateToSetting(item.href)}
            >
              <div className="flex items-center gap-4 mb-3">
                <div className="p-2 bg-secondary rounded-lg">
                  <Icon className="h-6 w-6 text-primary" />
                </div>
                <h3 className="text-base font-semibold text-foreground">{item.title}</h3>
              </div>
              <p className="text-sm text-muted-foreground">{item.description}</p>
            </div>
          );
        })}
      </div>

      {user?.email === PLATFORM_ADMIN_EMAIL && (
        <div className="mt-8 p-6 border border-destructive/20 rounded-lg bg-destructive/5">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="text-lg font-semibold text-destructive">
                Zona de Perigo
              </h3>
              <p className="text-sm text-muted-foreground mt-1">
                Ações irreversíveis que afetam permanentemente o salão
              </p>
            </div>
            <Button
              variant="destructive"
              onClick={() => setShowDeleteDialog(true)}
              className="gap-2"
            >
              <Trash2 className="h-4 w-4" />
              Excluir Salão
            </Button>
          </div>
        </div>
      )}

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent className="w-[95vw] md:max-w-lg rounded-xl md:rounded-lg border-none shadow-2xl">
          <AlertDialogHeader>
            <AlertDialogTitle>
              Tem certeza que deseja excluir este salão?
            </AlertDialogTitle>
            <AlertDialogDescription>
              Esta ação não pode ser desfeita. Todos os dados do salão,
              incluindo agendamentos, serviços, usuários e configurações serão
              permanentemente excluídos do sistema.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="flex-col-reverse sm:flex-row gap-2">
            <AlertDialogCancel disabled={isDeleting} className="w-full sm:w-auto">
              Cancelar
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDeleteSalon}
              disabled={isDeleting}
              className="w-full sm:w-auto bg-destructive hover:bg-destructive/90"
            >
              {isDeleting ? "Excluindo..." : "Excluir Permanentemente"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </EasySalonLayout>
  );
}
